// HTML example:
/*
<div id="outfitElement">Loading outfits...</div>
<button id="loadBtn">Load outfits</button>
*/

// 1. GET request with fetch (async/await)
const outfitElement = document.getElementById("outfitElement");
const loadBtn = document.getElementById("loadBtn");

loadBtn.addEventListener("click", async () => {
  try {
    outfitElement.classList.add("loading");
    const response = await fetch("https://api.example.com/outfits");
    if (!response.ok) throw new Error("Network error");
    const data = await response.json();
    outfitElement.textContent = data.outfits || "New outfits!";
    outfitElement.classList.remove("loading");
    outfitElement.classList.add("loaded");
  } catch (error) {
    outfitElement.textContent = "Error: Outfits not loaded!";
  }
});

// 2. POST request with fetch
loadBtn.addEventListener("click", async () => {
  try {
    const response = await fetch("https://api.example.com/add-outfit", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ "name": "Trendy Shirt", "type": "Summer" })
    });
    if (!response.ok) throw new Error("Network error");
    const data = await response.json();
    outfitElement.textContent = data.message || "Outfit added!";
  } catch (error) {
    outfitElement.textContent = "Error!";
  }
});

// 3. fetch with then
loadBtn.addEventListener("click", () => {
  fetch("https://api.example.com/outfits")
    .then(response => {
      if (!response.ok) throw new Error("Network error");
      return response.json();
    })
    .then(data => {
      outfitElement.textContent = data.outfits || "New outfits!";
    })
    .catch(error => {
      outfitElement.textContent = "Error: Outfits not loaded!";
    });
});

